SET day_of_week = #{dayOfWeek},
    method_code = #{methodCode},
    generator_code = #{generatorCode},
    set_count = #{setCount},
    analysis_draw_count = #{analysisDrawCount},
    sort_order = #{sortOrder},
    use_yn = #{useYn}
WHERE user_seq = #{userSeq}
  AND rule_id = #{ruleId}

